const i = $input.first().json || {};
const h = i.headers || {};
const cookieHeader = (h.cookie ?? h.Cookie ?? '').toString();
const m = cookieHeader.match(/(?:^|;\s*)ba_session=([^;]+)/);
const session_token = m ? m[1] : '';
return [{ json: { session_token } }];

const i = $input.first().json || {};
const body = $('Webhook - Citas Admin').first().json.body || {};
const action = body.action || '';
const auth_ok = !i.error && !!i.payload?.user_id;
const user_id = auth_ok ? Number(i.payload.user_id) : 0;

const params = [
  user_id,
  Number(body.barberia_id ?? 0),
  action,
  Number(body.id ?? body.cita_id ?? 0),
  body.barbero_id ? Number(body.barbero_id) : null,
  body.servicio_id ? Number(body.servicio_id) : null,
  auth_ok
];

return [{ json: { 
  auth_ok, 
  user_id, 
  barberia_id: Number(body.barberia_id ?? 0),
  action,
  cita_id: Number(body.id ?? body.cita_id ?? 0),
  params,
  body
} }];

const i = $input.first().json || {};
const claims = $('Code - claims input').first().json;

let ok = false;
let status_code = 200;
let message = '';

if (!i.auth_ok_jwt || !i.auth_ok) {
  status_code = 401;
  message = 'Sesion no valida';
} else if (!i.barberia_ok) {
  status_code = 403;
  message = 'No tienes permisos para esta barberia';
} else if (!i.barbero_ok) {
  status_code = 400;
  message = 'El barbero no pertenece a esta barberia o no existe';
} else if (!i.servicio_ok) {
  status_code = 400;
  message = 'El servicio no pertenece a esta barberia o no existe';
} else if (!i.cita_ok) {
  status_code = 403;
  message = 'La cita no pertenece a esta barberia o no existe';
} else {
  ok = true;
}

return [{ json: { ok, status_code, message, action: claims.action, body: claims.body } }];

const i = $input.first().json || {};
const claims = $('Code - claims input').first().json;
const body = claims.body || {};
const action = claims.action || '';
let query = '';
let params = [];

let cliente_id = null;
if (action !== 'cancel_cita') {
  try {
    const clientRes = $('PG - upsert client').first().json;
    if (clientRes.error) {
      return [{ json: { ok: false, message: 'Error al registrar o buscar el cliente: ' + (clientRes.error.message || '') } }];
    }
    cliente_id = clientRes.id;
  } catch (e) {
  }
}

if (action === 'add_cita') {
  query = `
    INSERT INTO public.citas (
      barberia_id, cliente_nombre, cliente_tel, barbero_id, servicio_id, fecha, hora_inicio, estado, cliente_id
    )
    VALUES (
      $1, $2, $3, $4, $5, $6::date, $7::time, $8, $9
    )
    RETURNING *;
  `;
  params = [
    Number(body.barberia_id),
    body.cliente_nombre,
    body.cliente_tel,
    body.barbero_id ? Number(body.barbero_id) : null,
    body.servicio_id ? Number(body.servicio_id) : null,
    body.fecha,
    body.hora_inicio,
    body.estado || 'confirmada',
    cliente_id ? Number(cliente_id) : null
  ];
} else if (action === 'update_cita') {
  query = `
    UPDATE public.citas
    SET
      cliente_nombre = $2,
      cliente_tel = $3,
      barbero_id = $4,
      servicio_id = $5,
      fecha = $6::date,
      hora_inicio = $7::time,
      estado = $8,
      cliente_id = $9
    WHERE id = $10 AND barberia_id = $1
    RETURNING *;
  `;
  params = [
    Number(body.barberia_id),
    body.cliente_nombre,
    body.cliente_tel,
    body.barbero_id ? Number(body.barbero_id) : null,
    body.servicio_id ? Number(body.servicio_id) : null,
    body.fecha,
    body.hora_inicio,
    body.estado || 'confirmada',
    cliente_id ? Number(cliente_id) : null,
    Number(body.id)
  ];
} else if (action === 'cancel_cita') {
  query = `
    UPDATE public.citas
    SET estado = 'cancelada'
    WHERE id = $1 AND barberia_id = $2
    RETURNING *;
  `;
  params = [
    Number(body.id),
    Number(body.barberia_id)
  ];
} else {
  return [{ json: { ok: false, message: 'Accion no permitida o desconocida.' } }];
}

return [{ json: { ok: true, query, params } }];

const input = $input.first().json;
if (input.error) {
  let errMsg = input.message || (input.error && input.error.description) || 'Error al ejecutar consulta en base de datos.';
  errMsg = errMsg.replace(/^ERROR:\s*/, '').split('\n')[0];
  if (errMsg.includes('ex_citas_no_solape')) {
    errMsg = 'El barbero seleccionado ya tiene una cita agendada en ese horario.';
  }
  return [{ json: { ok: false, status_code: 400, message: errMsg } }];
}
return [{ json: { ok: true, data: input } }];

